<?php
 namespace WPAICG\Images\Manager\Ajax; use WPAICG\Shortcodes\AIPKit_Image_Generator_Shortcode; use WP_Query; if (!defined('ABSPATH')) { exit; } function ajax_load_more_image_history_logic(): void { check_ajax_referer('aipkit_image_generator_nonce', '_ajax_nonce'); if (!is_user_logged_in()) { wp_send_json_error(['message' => __('You must be logged in to view history.', 'gpt3-ai-content-generator')], 403); return; } $page = isset($_POST['page']) ? absint($_POST['page']) : 2; $shortcode_mode = isset($_POST['shortcode_mode']) ? sanitize_key(wp_unslash((string) $_POST['shortcode_mode'])) : 'both'; if (!in_array($shortcode_mode, ['generate', 'edit', 'both'], true)) { $shortcode_mode = 'both'; } $allow_edit_action = in_array($shortcode_mode, ['edit', 'both'], true); $user_id = get_current_user_id(); if (!class_exists(AIPKit_Image_Generator_Shortcode::class)) { $shortcode_path = WPAICG_PLUGIN_DIR . 'classes/shortcodes/class-aipkit-image-generator-shortcode.php'; if (file_exists($shortcode_path)) { require_once $shortcode_path; } } if (!class_exists(AIPKit_Image_Generator_Shortcode::class)) { wp_send_json_error(['message' => __('Image history renderer is unavailable.', 'gpt3-ai-content-generator')], 500); return; } $query = new WP_Query(AIPKit_Image_Generator_Shortcode::build_history_query_args($user_id, $page)); $html_items = ''; ob_start(); if ($query->have_posts()) { while ($query->have_posts()) : $query->the_post(); echo AIPKit_Image_Generator_Shortcode::render_history_item((int) get_the_ID(), $allow_edit_action); endwhile; } $html_items = ob_get_clean(); wp_reset_postdata(); $has_more = ($page < $query->max_num_pages); wp_send_json_success([ 'html' => $html_items, 'has_more' => $has_more ]); } 